"use client"

import { useEffect, useState } from "react"
import { useAuth } from "@/lib/auth-context"
import { useRouter } from "next/navigation"
import { DashboardHeader } from "@/components/dashboard-header"
import { MarketDataGrid } from "@/components/manager/market-data-grid"
import { useMarketData } from "@/lib/hooks/useMarketData"
import { LocalDB } from "@/lib/local-storage/db"

export default function MarketDataPage() {
  const { user, loading } = useAuth()
  const router = useRouter()
  const [dataLoading, setDataLoading] = useState(true)
  const [securities, setSecurities] = useState<any[]>([])

  useEffect(() => {
    if (!loading && !user) {
      router.push("/auth/login")
      return
    }

    if (user && user.role !== "portfolio_manager") {
      router.push("/auth/login")
      return
    }

    if (user) loadData()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, loading])

  const loadData = async () => {
    setDataLoading(true)
    try {
      // Use securities stored in LocalDB (created during initializeDatabase)
      const secs = await LocalDB.getSecurities()
      setSecurities(secs.slice(0, 50))
    } catch (err) {
      console.error(err)
    } finally {
      setDataLoading(false)
    }
  }

  // Hook for simulated realtime updates; keeps UI in sync with LocalDB securities
  const { securities: liveSecurities } = useMarketData(2500)

  // keep local state in sync with live updates
  useEffect(() => {
    if (liveSecurities && liveSecurities.length) setSecurities(liveSecurities.slice(0, 50))
  }, [liveSecurities])

  if (loading || dataLoading || !user) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <div className="text-center">
          <div className="h-8 w-8 animate-spin rounded-full border-4 border-blue-600 border-t-transparent mx-auto mb-4"></div>
          <p className="text-gray-600">Loading...</p>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <DashboardHeader user={user} />

      <main className="container mx-auto p-6">
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900">Market Data</h1>
          <p className="text-gray-600">Real-time and historical market data for securities</p>
        </div>

        <MarketDataGrid securities={securities || []} />
      </main>
    </div>
  )
}
