// Lightweight sessionStorage-backed score cache for manager components
type ScoreEntry = { score: number; ts: number }

const CACHE_KEY = "manager_opportunity_scores_v1"

export async function getCachedScores(): Promise<Record<string, ScoreEntry>> {
  if (typeof window === "undefined") return {}
  const raw = sessionStorage.getItem(CACHE_KEY)
  if (!raw) return {}
  try {
    return JSON.parse(raw) as Record<string, ScoreEntry>
  } catch (e) {
    return {}
  }
}

export async function setCachedScores(cache: Record<string, ScoreEntry>) {
  if (typeof window === "undefined") return
  try {
    sessionStorage.setItem(CACHE_KEY, JSON.stringify(cache))
  } catch (e) {
    // ignore storage errors
  }
}

// compute missing or stale scores using computeFn. computeFn receives a security and must return a number.
export async function computeAndCacheScores(
  securities: any[],
  computeFn: (s: any) => Promise<number>,
  ttlMs = 30 * 1000,
): Promise<Record<string, number>> {
  const now = Date.now()
  const existing = await getCachedScores()
  const result: Record<string, number> = {}

  // prepare list of items to compute
  const toCompute: any[] = []
  for (const s of securities) {
    const ent = existing[s.id]
    if (ent && now - ent.ts < ttlMs) {
      result[s.id] = ent.score
    } else {
      toCompute.push(s)
    }
  }

  for (const s of toCompute) {
    try {
      const score = await computeFn(s)
      result[s.id] = score
      existing[s.id] = { score, ts: Date.now() }
    } catch (e) {
      existing[s.id] = { score: 0, ts: Date.now() }
      result[s.id] = 0
    }
  }

  // persist updated cache
  await setCachedScores(existing)
  return result
}

export async function clearScoreCache() {
  if (typeof window === "undefined") return
  try {
    sessionStorage.removeItem(CACHE_KEY)
  } catch (e) {}
}
